struct(TODATETIMEOFFSET(DATETIMEFROMPARTS(DATEPART(YEAR, (StartValue + INTERVAL 2 DAY)), DATEPART(MONTH, (StartValue + INTERVAL 2 DAY)), DATEPART(DAY, (StartValue + INTERVAL 2 DAY)), 0, 0, 0, 0), DATEPART(TZOFFSET, (StartValue + INTERVAL 2 DAY))) AS high, TODATETIMEOFFSET(DATETIMEFROMPARTS(DATEPART(YEAR, Value), DATEPART(MONTH, Value), DATEPART(DAY, Value), 0, 0, 0, 0), DATEPART(TZOFFSET, Value)) AS low)